public class Solution {
    public static long solve(long[] nums) {
        int n = nums.length;
        boolean[] isPrime = new boolean[n + 1];
        for (int i = 2; i <= n; i++) {
            isPrime[i] = true;
        }
        for (int i = 2; i * i <= n; i++) {
            if (isPrime[i]) {
                for (int j = i * i; j <= n; j += i) {
                    isPrime[j] = false;
                }
            }
        }

        int[] dist = new int[n];
        Arrays.fill(dist, -1);
        dist[0] = 0;

        Queue<Integer> q = new LinkedList<>();
        q.add(0);

        while (!q.isEmpty()) {
            int i = q.poll();
            if (i == n - 1) break;
            if (dist[i] == -1) continue;

            // Move to adjacent cells
            if (i > 0 && dist[i - 1] == -1) {
                dist[i - 1] = dist[i] + 1;
                q.add(i - 1);
            }
            if (i < n - 1 && dist[i + 1] == -1) {
                dist[i + 1] = dist[i] + 1;
                q.add(i + 1);
            }

            // Prime teleport
            if (isPrime[(int) nums[i]]) {
                long p = nums[i];
                for (int j = 0; j < n; j++) {
                    if (nums[j] % p == 0 && j != i && dist[j] == -1) {
                        dist[j] = dist[i] + 1;
                        q.add(j);
                    }
                }
            }
        }

        return dist[n - 1];
    }
}
